/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CARROCERIA_INCIDENCIA_HISTORICO_ai` AFTER INSERT ON `CARROCERIA_INCIDENCIA_HISTORICO` FOR EACH ROW
BEGIN 

UPDATE STK_ARTICULOS  Join MRP_CANTIDAD_ARTICULO_MODELO ON stkarticulo_id = id_stkarticulo set dem_diaria = 
(SELECT (sum((
                  (SELECT porciento_incidencia
                   FROM CARROCERIA_INCIDENCIA_HISTORICO HIS
                   WHERE HIS.nrocar = CARROCERIA.nrocar
                   ORDER BY fecha DESC LIMIT 1) / 100) * cantidad_modelo) *
             (SELECT tack_time
              FROM PROD_LINEAS
              WHERE id_linea=1)) AS "total"
   FROM MRP_CANTIDAD_ARTICULO_MODELO
   JOIN CARROCERIA ON (CARROCERIA.nrocar = MRP_CANTIDAD_ARTICULO_MODELO.carroceria_id)
   WHERE ((MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id = id_stkarticulo))
   GROUP BY stkarticulo_id), 

    stock_reposicion = 
(SELECT (STK_ARTICULOS.demprov * (sum((
                                           (SELECT porciento_incidencia
                                            FROM CARROCERIA_INCIDENCIA_HISTORICO HIS
                                            WHERE HIS.nrocar = CARROCERIA.nrocar
                                            ORDER BY fecha DESC LIMIT 1) / 100) * cantidad_modelo) *
                                      (SELECT tack_time
                                       FROM PROD_LINEAS
                                       WHERE id_linea=1))) + STK_ARTICULOS.stock_minimo AS "stock_reposicion"
   FROM MRP_CANTIDAD_ARTICULO_MODELO
   JOIN CARROCERIA ON (CARROCERIA.nrocar = MRP_CANTIDAD_ARTICULO_MODELO.carroceria_id)
   WHERE ((MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id =id_stkarticulo))
   GROUP BY stkarticulo_id) 
;

 END */;;
DELIMITER ;
