/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CPS_DETALLE_au` AFTER UPDATE ON `CPS_DETALLE` FOR EACH ROW
BEGIN
    DECLARE v_total_detalles INT;
    DECLARE v_total_cumplidos INT;

    /* Obtengo el total de registros en CPS_DETALLE para la orden */
    SELECT COUNT(*) INTO v_total_detalles
    FROM CPS_DETALLE 
    WHERE cpsmovimiento_id = NEW.cpsmovimiento_id;

    /* Obtengo el total de registros donde cumplido = 1 */
    SELECT COUNT(*) INTO v_total_cumplidos
    FROM CPS_DETALLE 
    WHERE cpsmovimiento_id = NEW.cpsmovimiento_id AND cumplido = 1;

    /* Si todos los registros tienen cumplido = 1, actualizo el estado */
    IF v_total_detalles > 0 AND v_total_detalles = v_total_cumplidos THEN
        UPDATE CPS_MOVIMIENTOS 
        SET cpsestado_id = 2 
        WHERE id_cpsmovimiento = NEW.cpsmovimiento_id;
    END IF;
END */;;
DELIMITER ;
