/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CPS_MOVIMIENTOS_bi` BEFORE INSERT ON `CPS_MOVIMIENTOS` FOR EACH ROW
BEGIN
if (NEW.regcuenta_id = 0) then
SET NEW.regcuenta_id = (select id_regcuenta from REG_CUENTA WHERE subsistema_id = '01' and REG_CUENTA.nro_cuenta = NEW.ctacod);
END IF;

if (NEW.regforma_id = 0  ) then 
set NEW.regforma_id = (select id_regforma from REG_FORMAS where formapago_old = NEW.fpago limit 1);
end if;

IF (NEW.calificacion_calidad = 'X') THEN 
SET NEW.cpsestado_id = 0;
END IF;


END */;;
