/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `afterinsertCTBREGIS` AFTER INSERT ON `CTBREGIS` FOR EACH ROW
BEGIN

	insert ignore into CTB_MOVIMIENTOS  set `nro_minuta`= NEW.regmin , 
											`fecha_movimiento` = NEW.regfec, 
											`referencia` = NEW.regref, 
											`ejercicio_id` = (select id_ejercicio from CTB_EJERCICIOS where NEW.regfec <= finaliza and NEW.regfec >= comienza),
											`concepto_id` = 1, 
											`regmovim_id` = (select id_regmovim from REG_MOVIMIENTOS REG where REG.regmin = NEW.regmin and REG.nro_movimiento = NEW.regnro and REG.reg_fecha = NEW.regfec limit 1), 
											`fecha_modificacion` = NEW.regfec;

	insert ignore into  `CTB_DETALLES` SET `cuenta_id` = NEW.ctbcod, 
											`doh` = (NEW.regdoh - 1 ), 
											`importe` = NEW.regimp , 
											`referencia` = NEW.regref,  
											`orden` = NEW.regord, 
											`ctbregis_id` = NEW.id_ctbregis, 
											`ctbcentro_id` = NEW.idcos,
											`movimiento_id` = (select CTB.id_movimiento from CTB_MOVIMIENTOS as CTB where CTB.nro_minuta = NEW.regmin and CTB.fecha_movimiento = NEW.regfec limit 1);

END */;;
DELIMITER ;
