/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CTBREGIS_au` AFTER UPDATE ON `CTBREGIS` FOR EACH ROW
BEGIN

       declare REGID integer;
       declare CTBID integer;

        set REGID = (select id_regmovim from REG_MOVIMIENTOS REG where REG.regmin = NEW.regmin and REG.nro_movimiento = NEW.regnro and REG.reg_fecha = NEW.regfec limit 1);
	insert ignore into CTB_MOVIMIENTOS  set `nro_minuta`= NEW.regmin , 
											`fecha_movimiento` = NEW.regfec, 
											`referencia` = NEW.regref, 
											`ejercicio_id` = date_format(NEW.regfec, '%y' ),
											`concepto_id` = 1, 
											`regmovim_id` = REGID, 
											`fecha_modificacion` = NEW.regfec;

        delete FROM CTB_DETALLES where ctbregis_id = NEW.id_ctbregis and NEW.id_ctbregis != 0;

        SET CTBID = (select CTB.id_movimiento from CTB_MOVIMIENTOS as CTB where CTB.nro_minuta = NEW.regmin and CTB.fecha_movimiento = NEW.regfec limit 1);

	insert ignore into  `CTB_DETALLES` SET `cuenta_id` = NEW.ctbcod, 
											`doh` = (NEW.regdoh - 1 ), 
											`importe` = NEW.regimp , 
											`referencia` = NEW.regref,  
											`orden` = NEW.regord, 
											`ctbregis_id` = NEW.id_ctbregis,
											`ctbcentro_id` = NEW.idcos,
											`movimiento_id` = CTBID;

       update CTB_MOVIMIENTOS SET `regmovim_id` = REGID
              where regmovim_id = NULL AND id_movimiento = CTBID;

/*
update  `CTB_DETALLES` SET `cuenta_id` = NEW.ctbcod, 
											`doh` = (NEW.regdoh - 1 ), 
											`importe` = NEW.regimp , 
											`referencia` = NEW.regref,  
											`orden` = NEW.regord, 
											`ctbregis_id` = NEW.id_ctbregis, 
											`movimiento_id` = (select CTB.id_movimiento from CTB_MOVIMIENTOS as CTB where CTB.nro_minuta = NEW.regmin and CTB.fecha_movimiento = NEW.regfec limit 1)
where ctbregis_id = NEW.id_ctbregis and NEW.id_ctbregis != 0;
*/
END */;;
DELIMITER ;
