/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CTBREGIS_ad` AFTER DELETE ON `CTBREGIS` FOR EACH ROW
BEGIN

DELETE from CTB_DETALLES where ctbregis_id = OLD.id_ctbregis and ctbregis_id != 0 limit 1;
END */;;
