  `fecha_movimiento` date DEFAULT NULL,
  `referencia` varchar(70) DEFAULT NULL,
  `ejercicio_id` int(10) NOT NULL,
  `concepto_id` int(10) NOT NULL,
  `regmovim_id` int(11) DEFAULT NULL,
  `fecha_modificacion` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `usuario_modificacion` varchar(45) DEFAULT NULL,
  `cajregistro_id` int(11) DEFAULT NULL,
  `genmoneda_id` int(11) DEFAULT NULL,
  `debe` decimal(16,2) DEFAULT NULL,
  `haber` decimal(16,2) DEFAULT NULL,
  `ctbgrupo_id` int(11) NOT NULL,
  `cajmovimiento_id` int(11) DEFAULT NULL,
  PRIMARY KEY (`id_movimiento`),
  UNIQUE KEY `indice_movimiento` (`ejercicio_id`,`concepto_id`,`fecha_movimiento`,`nro_minuta`,`fecha_modificacion`),
  KEY `fk_CTB_MOVIMIENTOS_CTB_EJERCICIOS1` (`ejercicio_id`),
  KEY `fk_CTB_MOVIMIENTOS_CTB_CONCEPTOS1` (`concepto_id`),
  KEY `Nro_Minuta` (`nro_minuta`),
  KEY `regmovim_id` (`regmovim_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1260665 DEFAULT CHARSET=utf8;
