/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CTB_MOVIMIENTOS_bi` BEFORE INSERT ON `CTB_MOVIMIENTOS` FOR EACH ROW
BEGIN


         SET NEW.ejercicio_id =  (SELECT id_ejercicio FROM CTB_EJERCICIOS WHERE CTB_EJERCICIOS.comienza <= NEW.fecha_movimiento and  CTB_EJERCICIOS.finaliza >= NEW.fecha_movimiento LIMIT 1 );




	SET @tipo_renumeracion = (SELECT tipo_renumeracion FROM `CTB_EJERCICIOS` WHERE CTB_EJERCICIOS.id_ejercicio = NEW.ejercicio_id);

	IF (@tipo_renumeracion=0) THEN
		SET NEW.nro_minuta = (SELECT ifnull(max(nro_minuta), 0) + 1 
		                        FROM CTB_MOVIMIENTOS 
		                       WHERE MONTH(CTB_MOVIMIENTOS.fecha_movimiento) = MONTH(NEW.fecha_movimiento) 
		                         AND YEAR(CTB_MOVIMIENTOS.fecha_movimiento) = YEAR(NEW.fecha_movimiento) 
		                         AND CTB_MOVIMIENTOS.ejercicio_id = NEW.ejercicio_id);
	ELSE
		SET NEW.nro_minuta = (SELECT ifnull(max(nro_minuta), 0) + 1 
		                        FROM CTB_MOVIMIENTOS 
		                       WHERE YEAR(CTB_MOVIMIENTOS.fecha_movimiento) = YEAR(NEW.fecha_movimiento) 
		                         and CTB_MOVIMIENTOS.ejercicio_id = NEW.ejercicio_id); 
	END IF;

END */;;
DELIMITER ;
