/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `CTB_MOVIMIENTOS_ai` AFTER INSERT ON `CTB_MOVIMIENTOS` FOR EACH ROW
begin
/*
update LOG_REGION
set porcentaje_region = (
SELECT  
(sum( (case when cuenta_id = cuenta_importacion then round(importe, 2) * (case when doh = 1 then -1 else 1 end) else 0 end))) / (sum( (case when ctbgrupo_id = 6 then round(importe, 2) * (case when doh = 1 then -1 else 1 end) else 0 end))) * 100

from 
 REG_MOVIMIENTOS 
left join CTB_MOVIMIENTOS on  REG_MOVIMIENTOS.id_regmovim = CTB_MOVIMIENTOS.regmovim_id 

LEFT JOIN REG_CUENTA on ( REG_CUENTA.id_regcuenta = REG_MOVIMIENTOS.regcuenta_id ) and ( REG_CUENTA.estcod = 0 )
JOIN CTB_DETALLES on ( CTB_DETALLES.movimiento_id = id_movimiento ) 
JOIN CTBCUENT on ( CTBCUENT.ctbcod = CTB_DETALLES.cuenta_id ) 
left JOIN CTB_CUENTA_GRUPO on ( CTB_CUENTA_GRUPO.ctbcuenta_id = CTB_DETALLES.cuenta_id ) 
left JOIN CTB_GRUPO_REPORTE on ( CTB_GRUPO_REPORTE.id_ctbgrupo = ctbgrupo_id )  

where REG_MOVIMIENTOS.logregion_id = id_logregion and    REG_MOVIMIENTOS.bienes_capital = 0  
 AND REG_MOVIMIENTOS.fecha_movimiento >= '2018-01-01' 
 group by id_logregion);
*/
end */;;
DELIMITER ;
