/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `FACREMIT_bi` BEFORE INSERT ON `FACREMIT` FOR EACH ROW
begin

IF NEW.remnro = 0 THEN
SET NEW.remnro = (select OCPRECIB.nrorec from OCPRECIB WHERE  NEW.ocpnro = OCPRECIB.ocpnro and NEW.ctacod = OCPRECIB.ctacod and OCPRECIB.nrorec != 0 and OCPRECIB.fecrec = NEW.remfec);
