/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `FACREMIT_ai` AFTER INSERT ON `FACREMIT` FOR EACH ROW
BEGIN
    DECLARE v_id_regmovim BIGINT;
    DECLARE v_id_regcuenta INT;
    DECLARE v_cps_id INT;

    -- 1. Obtener el ID de la cuenta en saldivia_sa
    SELECT id_regcuenta INTO v_id_regcuenta 
    FROM saldivia_sa.REG_CUENTA 
    WHERE subsistema_id = '01' AND nro_cuenta = NEW.ctacod 
    LIMIT 1;

    -- 2. Obtener el ID del encabezado de la OC
    SELECT id_cpsmovimiento INTO v_cps_id 
    FROM saldivia.CPS_MOVIMIENTOS 
    WHERE ctacod = NEW.ctacod 
      AND cps_numero = NEW.ocpnro 
      AND cpsfecha = NEW.ocpfec 
    LIMIT 1;

    -- 3. Insertar el Encabezado en REG_MOVIMIENTOS
    INSERT INTO saldivia_sa.REG_MOVIMIENTOS (
        subsistema_id, regcuenta_id, concepto_id, referencia_movimiento, 
        nro_movimiento, puesto_movimiento, fecha_movimiento, reg_fecha, 
        fpv_movimiento, cpsmovimiento_id, letra_movimiento, vencimiento_movimiento, 
        reg_periodo, nro_cuenta, presentado, login, remito, succod,
        neto_movimiento, importe_iva, importe_movimiento, saldo_movimiento
    ) 
    VALUES (
        '01', v_id_regcuenta, 127, 'Recepcion mercaderia', 
        NEW.remnro, NEW.remnpv, NEW.remfec, NEW.movfec__1, 
        NEW.ocpfec, v_cps_id, 'R', NEW.remfec, 
        DATE_FORMAT(NEW.remfec, '%Y%m'), NEW.ctacod, 0, 'histrix', 1, 1,
        0, 0, 0, 0
    );

    SET v_id_regmovim = LAST_INSERT_ID();

    -- 4. Insertar Detalles con IVA prorrateado por unidad
    INSERT INTO saldivia_sa.REG_DETALLES (
        regmovim_id, sercod, descripcion_detalle, codigo_detalle, 
        cantidad_detalle, cantidad_entregada,
        precio_venta, neto_detalle, iva_detalle, total_detalle,
        alicuota_iva, facservicio_id, codigo_serie, color_id, referencia_detalle
    )
    SELECT 
        v_id_regmovim, 
        1, 
        S.descripcion, 
        S.artcod, 
        S.movcant, 
        S.movcant,
        D.costo_unitario,
        (S.movcant * D.costo_unitario),
        -- Calculamos IVA unitario (IVA Total / Cantidad OC) y multiplicamos por lo recibido
        (S.movcant * (D.importe_iva / D.cantidad_compra)), 
        (S.movcant * D.costo_unitario) + (S.movcant * (D.importe_iva / D.cantidad_compra)),
        IF(D.costo_unitario > 0, ((D.importe_iva / D.cantidad_compra) / D.costo_unitario) * 100, 0),
        0, '', 0, CONCAT('OC: ', NEW.ocpnro)
    FROM saldivia.STKINMOV S
    INNER JOIN saldivia.CPS_DETALLE D ON D.cpsmovimiento_id = v_cps_id 
        AND D.stkarticulo_id = S.artcod
    WHERE S.movnro = NEW.remnro 
      AND S.movnpv = NEW.remnpv 
      AND S.ctacod = NEW.ctacod
      AND S.movfec = NEW.movfec__1;

    -- 5. Actualizar totales del encabezado
    UPDATE saldivia_sa.REG_MOVIMIENTOS 
    SET 
        neto_movimiento = (SELECT IFNULL(SUM(neto_detalle), 0) FROM saldivia_sa.REG_DETALLES WHERE regmovim_id = v_id_regmovim),
        importe_iva = (SELECT IFNULL(SUM(iva_detalle), 0) FROM saldivia_sa.REG_DETALLES WHERE regmovim_id = v_id_regmovim),
        importe_movimiento = (SELECT IFNULL(SUM(total_detalle), 0) FROM saldivia_sa.REG_DETALLES WHERE regmovim_id = v_id_regmovim),
        saldo_movimiento = (SELECT IFNULL(SUM(total_detalle), 0) FROM saldivia_sa.REG_DETALLES WHERE regmovim_id = v_id_regmovim)
    WHERE id_regmovim = v_id_regmovim;

END */;;
DELIMITER ;
