CREATE TABLE `FICHADAS` (
  `tarjeta` int(11) NOT NULL DEFAULT '0',
  `fechaChar` varchar(8) NOT NULL DEFAULT '',
  `crc` time NOT NULL DEFAULT '00:00:00',
  `reloj` varchar(5) NOT NULL DEFAULT '0',
  `codigo` varchar(10) NOT NULL DEFAULT '',
  `fecha` date DEFAULT '0000-00-00',
  `hora` time NOT NULL DEFAULT '00:00:00',
  `borrado` tinyint(4) NOT NULL,
  `marca` tinyint(4) NOT NULL DEFAULT '0',
  `insertkey` varchar(80) NOT NULL,
  `id_fichada` int(11) NOT NULL AUTO_INCREMENT,
  PRIMARY KEY (`id_fichada`),
  UNIQUE KEY `insertKey` (`insertkey`),
  KEY `TJTFECHA` (`tarjeta`,`fecha`),
  KEY `MARCA` (`marca`),
  KEY `tjtfec2` (`tarjeta`,`fecha`,`borrado`),
  KEY `tjt` (`tarjeta`),
  KEY `fec` (`fecha`)
