/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `beforeinsertFICHADAS` BEFORE INSERT ON `FICHADAS` FOR EACH ROW
BEGIN
set NEW.codigo = replace(NEW.codigo, '
','');
set NEW.insertkey = md5(replace(trim(CONCAT(NEW.tarjeta , NEW.fechaChar , NEW.crc , NEW.reloj , NEW.codigo)),'
',''));
SET NEW.fecha = STR_TO_DATE(NEW.fechaChar, '%d/%m/%y');

IF (STR_TO_DATE(NEW.fechaChar, '%d/%m/%y') >= '2008-07-01' and  DAYOFWEEK( NEW.fecha )  != 7) THEN
   SET NEW.hora = (case when NEW.crc > '15:15:00' then CONCAT('15:0', substring(NEW.crc, 5, 1)) else NEW.crc end);
END IF;
IF (NEW.fecha >= '2008-07-01' and  DAYOFWEEK( NEW.fecha )  = 7) THEN
   SET NEW.hora = (case when NEW.crc > '11:15:00' then CONCAT('11:0', substring(NEW.crc, 5, 1)) else NEW.crc end);
END IF;

IF (STR_TO_DATE(NEW.fechaChar, '%d/%m/%y') >= '2008-12-16') THEN
   SET NEW.hora = (case when NEW.crc > '16:15:00' then CONCAT('16:0', substring(NEW.crc, 5, 1)) else NEW.crc end);
END IF;
IF (NEW.fecha >= '2008-12-16' and DAYOFWEEK( NEW.fecha )  = 6) THEN
   SET NEW.hora = (case when NEW.crc > '15:15:00' then CONCAT('15:0', substring(NEW.crc, 5, 1)) else NEW.crc end);
END IF;

IF (NEW.reloj = '999') THEN
	SET NEW.borrado = 51;
END IF;
END */;;
DELIMITER ;
