/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `insertFICHADAS` AFTER INSERT ON `FICHADAS` FOR EACH ROW BEGIN
	REPLACE INTO FICHADADIA (tarjeta, legajo, fecha, h1, h2, h3, h4, feriado, hingreso, hegreso, max_extras_50)
	SELECT 
	NEW.tarjeta, 
	PERSONAL.legajo ,
	NEW.fecha, 
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = NEW.tarjeta and FIC.borrado = 0 and FIC.fecha = NEW.fecha order by crc limit 0,1), 
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = NEW.tarjeta and FIC.borrado = 0 and FIC.fecha = NEW.fecha order by crc limit 1,1),
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = NEW.tarjeta and FIC.borrado = 0 and FIC.fecha = NEW.fecha order by crc limit 2,1),
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = NEW.tarjeta and FIC.borrado = 0 and FIC.fecha = NEW.fecha order by crc limit 3,1),
	(select count(*) from FERIADOS where FERIADOS.idFeriado = NEW.fecha),
	(select HIST.ingreso from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(NEW.fecha) and HIST.desdeFecha <= NEW.fecha order by HIST.desdeFecha DESC limit 1),
	(select HIST.egreso  from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(NEW.fecha) and HIST.desdeFecha <= NEW.fecha order by HIST.desdeFecha DESC limit 1),
	(select HIST.extras50  from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(NEW.fecha) and HIST.desdeFecha <= NEW.fecha order by HIST.desdeFecha DESC limit 1)
	
	from PERSONAL_TARJETA INNER JOIN PERSONAL on PERSONAL.idPersona = PERSONAL_TARJETA.idPersona and
						    (PERSONAL.fechaEgreso >= NEW.fecha or PERSONAL.fechaEgreso = '0000-00-00')
				    
		where PERSONAL_TARJETA.tarjeta 	   = NEW.tarjeta  and 
		      PERSONAL_TARJETA.fechaDesde <= NEW.fecha 
		order by PERSONAL_TARJETA.fechaDesde DESC limit 1;

END */;;
DELIMITER ;
