/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `deleteFICHADAS` AFTER DELETE ON `FICHADAS` FOR EACH ROW BEGIN
	REPLACE INTO FICHADADIA (tarjeta, legajo, fecha, h1, h2, h3, h4, feriado, hingreso, hegreso, max_extras_50)
