	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = OLD.tarjeta and FIC.borrado = 0 and FIC.fecha = OLD.fecha order by crc limit 0,1), 
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = OLD.tarjeta and FIC.borrado = 0 and FIC.fecha = OLD.fecha order by crc limit 1,1),
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = OLD.tarjeta and FIC.borrado = 0 and FIC.fecha = OLD.fecha order by crc limit 2,1),
	(select FIC.crc from FICHADAS as FIC where FIC.tarjeta = OLD.tarjeta and FIC.borrado = 0 and FIC.fecha = OLD.fecha order by crc limit 3,1),
	(select count(*) from FERIADOS where FERIADOS.idFeriado = OLD.fecha),
	(select HIST.ingreso from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(OLD.fecha) and HIST.desdeFecha <= OLD.fecha order by HIST.desdeFecha DESC limit 1),
	(select HIST.egreso  from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(OLD.fecha) and HIST.desdeFecha <= OLD.fecha order by HIST.desdeFecha DESC limit 1),
	(select HIST.extras50  from HORARIOHIST as HIST where HIST.dia = DAYOFWEEK(OLD.fecha) and HIST.desdeFecha <= OLD.fecha order by HIST.desdeFecha DESC limit 1)

	from PERSONAL_TARJETA INNER JOIN PERSONAL on PERSONAL.idPersona = PERSONAL_TARJETA.idPersona and
						    (PERSONAL.fechaEgreso >= OLD.fecha or PERSONAL.fechaEgreso = '0000-00-00')

		where PERSONAL_TARJETA.tarjeta 	   = OLD.tarjeta  and 
		      PERSONAL_TARJETA.fechaDesde <= OLD.fecha 
		order by PERSONAL_TARJETA.fechaDesde DESC limit 1;

END */;;
DELIMITER ;
