  `chasis_expte` varchar(30) NOT NULL COMMENT 'Expediente Chasis',
  `chasis_disposicion` varchar(20) NOT NULL COMMENT 'Disposicion Chasis',
  `chasis_eje_delantero` decimal(10,0) NOT NULL COMMENT 'Peso eje delantero',
  `chasis_eje_trasero` decimal(10,0) NOT NULL COMMENT 'Peso eje trasero',
  `chasis_modificacion` longtext NOT NULL COMMENT 'Modificacion chasis',
  `artcod_id` varchar(10) NOT NULL,
  `referencia` varchar(80) NOT NULL,
  `expediente_lcm_id` varchar(60) NOT NULL,
  `euro` varchar(60) NOT NULL,
  `capacidad_combustible` decimal(10,2) NOT NULL,
  `acompañante` int(1) NOT NULL DEFAULT '1',
  `auxiliar` int(1) NOT NULL,
  `guia` int(1) NOT NULL,
  `codigo_comercial` varchar(25) NOT NULL,
  `desc_comercial` varchar(30) NOT NULL,
