  KEY `marcod` (`marcod`),
  KEY `nrocar` (`nrocar`),
  KEY `modelo_id` (`modelo_id`),
  KEY `nrocar_baja` (`nrocar`,`baja`),
  KEY `baja` (`baja`),
  KEY `modelo_lcm_id` (`modelo_lcm_id`)
) ENGINE=InnoDB AUTO_INCREMENT=585 DEFAULT CHARSET=utf8 COMMENT='HOMOLOGACIONES POR MODELO';
