DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `ActualizaIvaCVId` BEFORE INSERT ON `IVAIMPORTES` FOR EACH ROW
BEGIN
SET NEW.ivacv_id = 
(CASE NEW.tipoiva WHEN 1 THEN
IFNULL((SELECT id_ivacompra FROM IVACOMPRAS WHERE fecreg = NEW.feciva and codcom = NEW.codcom and codlet = NEW.codlet and nronpv = NEW.nronpv and nrocom = NEW.nrocom and ctacod = NEW.ctacod), 0)
WHEN 2 THEN
IFNULL((SELECT id_ivaventa FROM IVAVENTAS WHERE fecreg = NEW.feciva and codcom = NEW.codcom and codlet = NEW.codlet and nronpv = NEW.nronpv and nrocom = NEW.nrocom and ctacod = NEW.ctacod), 0)
 END);
END */;;
DELIMITER ;
