--

DROP TABLE IF EXISTS `MRP_CANTIDAD_ARTICULO_MODELO`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `MRP_CANTIDAD_ARTICULO_MODELO` (
  `id_cantidad_articulo_modelo` int(11) NOT NULL AUTO_INCREMENT,
  `stkarticulo_id` varchar(20) NOT NULL,
  `cantidad_modelo` decimal(10,2) NOT NULL COMMENT 'expresaio en unidad de uso',
  `carroceria_id` int(11) NOT NULL,
  PRIMARY KEY (`id_cantidad_articulo_modelo`)
) ENGINE=InnoDB AUTO_INCREMENT=8751 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `MRP_CANTIDAD_ARTICULO_MODELO_ai` AFTER INSERT ON `MRP_CANTIDAD_ARTICULO_MODELO` FOR EACH ROW
BEGIN
DECLARE DIARIA FLOAT;
DECLARE REPOSICION FLOAT;
set DIARIA = (SELECT  (sum(((select porciento_incidencia from CARROCERIA_INCIDENCIA_HISTORICO HIS where HIS.nrocar = CARROCERIA.nrocar order by fecha DESC limit 1) / 100 ) * cantidad_modelo ) * (select tack_time from PROD_LINEAS WHERE id_linea=1)) as "total"  
from MRP_CANTIDAD_ARTICULO_MODELO JOIN STK_ARTICULOS on ( STK_ARTICULOS.id_stkarticulo = MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id ) JOIN CARROCERIA on ( CARROCERIA.nrocar = MRP_CANTIDAD_ARTICULO_MODELO.carroceria_id ) where ( ( MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id =NEW.stkarticulo_id ) ) group by stkarticulo_id);
set REPOSICION = (SELECT  ( STK_ARTICULOS.demprov * (sum(((select porciento_incidencia from CARROCERIA_INCIDENCIA_HISTORICO HIS where HIS.nrocar = CARROCERIA.nrocar order by fecha DESC limit 1) / 100 ) * cantidad_modelo ) * (select tack_time from PROD_LINEAS WHERE id_linea=1))) + STK_ARTICULOS.stock_minimo as "stock_reposicion" 
from MRP_CANTIDAD_ARTICULO_MODELO JOIN STK_ARTICULOS on ( STK_ARTICULOS.id_stkarticulo = MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id ) JOIN CARROCERIA on ( CARROCERIA.nrocar = MRP_CANTIDAD_ARTICULO_MODELO.carroceria_id ) where ( ( MRP_CANTIDAD_ARTICULO_MODELO.stkarticulo_id =NEW.stkarticulo_id ) ) group by stkarticulo_id);
UPDATE STK_ARTICULOS SET dem_diaria = DIARIA , stock_reposicion = REPOSICION where STK_ARTICULOS.id_stkarticulo = NEW.stkarticulo_id limit 1;

END */;;
DELIMITER ;
