/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `insertPrecioModelo` AFTER INSERT ON `PRECIOMODELO`
 FOR EACH ROW BEGIN
	INSERT  IGNORE into COTIZOPCIONES  ( idPrecio , idOpcion , descripcion , idSeccion )
	    SELECT CONCAT(NEW.nrocar, NEW.idGrupo, NEW.asientos + 1), idOpcion, descripcion, idSeccion FROM COTIZOPCIONES where COTIZOPCIONES.idPrecio = (select max(idPrecio) from PRECIOMODELO PM where PM.nrocar = NEW.nrocar
	    and PM.asientos = NEW.asientos AND PM.banbar = NEW.banbar and PM.idPrecio != NEW.idPrecio );
END */;;
