  `nrofab_id` int(11) NOT NULL,
  `valor_control` int(11) NOT NULL,
  `observacion_control` varchar(200) NOT NULL,
  `fecha_control` date NOT NULL,
  `conforme` tinyint(4) NOT NULL,
  `no_conforme` tinyint(4) NOT NULL,
  `no_aplica` tinyint(4) NOT NULL,
  `hora_control` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `controlado` tinyint(4) NOT NULL,
  `user_id` varchar(20) NOT NULL,
  `foto` varchar(200) DEFAULT NULL,
  `horas_retrabajo` decimal(4,2) NOT NULL,
  `controlcausal_id` int(11) NOT NULL,
  `legajo_personal` int(11) NOT NULL,
  `acciones_control` varchar(200) NOT NULL,
  `legajo_realizo` int(12) NOT NULL DEFAULT '0',
  `seccion_origen_id` varchar(100) NOT NULL,
  `seccion_calidad_id` int(11) NOT NULL,
  PRIMARY KEY (`id_controlmovim`),
  UNIQUE KEY `prodcontrol_id_nrofab_id` (`prodcontrol_id`,`nrofab_id`),
