  KEY `prodcontrol_id` (`prodcontrol_id`),
  KEY `foto` (`foto`),
  KEY `controlcausal_id` (`controlcausal_id`),
  CONSTRAINT `PROD_CONTROL_MOVIM_ibfk_1` FOREIGN KEY (`prodcontrol_id`) REFERENCES `PROD_CONTROLES` (`id_prodcontrol`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1804310 DEFAULT CHARSET=utf8;
