/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `PROD_CONTROL_MOVIM_bi` BEFORE INSERT ON `PROD_CONTROL_MOVIM` FOR EACH ROW
BEGIN

set NEW.fecha_control = now();

if (NEW.foto = '' or NEW.foto IS NULL ) then 
set NEW.foto = (select filename from HTX_MEDIA WHERE table_name = 'PROD_CONTROL_MOVIM'  and uid = concat(NEW.nrofab_id,'/controlcalidad/',NEW.prodcontrol_id) limit 1);
end if;


END */;;
