/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `PROD_CONTROL_MOVIM_ai` AFTER INSERT ON `PROD_CONTROL_MOVIM` FOR EACH ROW
BEGIN
IF (NEW.prodcontrol_id = 529)
THEN 
 UPDATE PEDCOTIZ SET ingresoLinea = DATE(NEW.hora_control)
 WHERE nrocha = NEW.nrofab_id;
END IF;

IF (NEW.prodcontrol_id = 488)
THEN 
 UPDATE PEDCOTIZ SET terminacion = DATE(NEW.hora_control)
 WHERE nrocha = NEW.nrofab_id;
END IF;

if ( ifnull((select orden_control from PROD_CONTROLES WHERE id_prodcontrol = NEW.prodcontrol_id and critico = 1 ), 0) = 1)
  then call ingresaCocheSeccion(NEW.nrofab_id, (select seccion_id from PROD_CONTROLES WHERE id_prodcontrol = NEW.prodcontrol_id));
end if;

END */;;
