/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `REG_IMPUTACIONES_ai` AFTER INSERT ON `REG_IMPUTACIONES` FOR EACH ROW
BEGIN

 UPDATE REG_MOVIMIENTOS set REG_MOVIMIENTOS.

 saldo_movimiento = REG_MOVIMIENTOS.importe_movimiento - (SELECT sum(REG.movimiento_imputacion) from REG_IMPUTACIONES AS REG where REG.regmovim0_id = NEW.regmovim0_id ) where REG_MOVIMIENTOS.id_regmovim = NEW.regmovim0_id;

END */;;
