/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `insertBREG_MOVIMIENTOS` BEFORE INSERT ON `REG_MOVIMIENTOS` FOR EACH ROW
BEGIN
	if (NEW.regcuenta_id = 0 or NEW.nro_cuenta != 0) then
	    set NEW.regcuenta_id = (select REG_CUENTA.id_regcuenta from REG_CUENTA WHERE REG_CUENTA.nro_cuenta = NEW.nro_cuenta and REG_CUENTA.subsistema_id = NEW.subsistema_id);
	end if;   
	if (NEW.nro_cuenta = 0)  then
	    set NEW.nro_cuenta = (select REG_CUENTA.nro_cuenta from REG_CUENTA WHERE REG_CUENTA.id_regcuenta = NEW.regcuenta_id );
	end if;    
	if (NEW.concepto_id = 0 or NEW.concod != 0) then
	    set NEW.concepto_id = (select id_concepto from REG_CONCEPTOS WHERE REG_CONCEPTOS.cod_concepto = NEW.concod and REG_CONCEPTOS.subsistema_id = NEW.subsistema_id);
	end if;   
	if ( NEW.concod = 0) then
	      SET NEW.concod = (SELECT cod_concepto FROM REG_CONCEPTOS WHERE id_concepto = NEW.concepto_id);
	end if; 
	if (NEW.subsistema_id = '04') then
		set NEW.fpv_movimiento = NEW.vencimiento_movimiento;
	end if;

END */;;
DELIMITER ;
