/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizoCostoArticulo_insert` AFTER INSERT ON `STKINSPR` FOR EACH ROW
BEGIN

        UPDATE STKINSUM set  STKINSUM.ultima_compra = NEW.fecult, STKINSUM.costo_calculado = round(case when (NEW.artcos * STKINSUM.valcps / STKINSUM.valuso ) > 0 then 
	NEW.artcos  else 	STKINSUM.artcos end, 2) where STKINSUM.artcod = NEW.artcod and STKINSUM.siscod = '01';
UPDATE STKPIEZA set recalc = recalc + 1 where STKPIEZA.articulo_hijo = NEW.artcod;
UPDATE STKPIEZA set recalc = recalc + 1 where STKPIEZA.idPadre = NEW.artcod;

REPLACE INTO STK_COSTO_HIST set articulo_id = NEW.artcod, anio_hist = YEAR(NEW.fecult), mes_hist = MONTH(NEW.fecult), costo_hist = NEW.artcos;

END */;;
DELIMITER ;
