/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizoCostoArticulo_update` AFTER UPDATE ON `STKINSPR` FOR EACH ROW
BEGIN
  declare padre varchar(10) DEFAULT '';
  declare outerpadre varchar(10) DEFAULT '';
  DECLARE done INT DEFAULT 0;
  DECLARE cur1 CURSOR FOR SELECT  trim(idPadre) FROM `STKPIEZA` where STKPIEZA.articulo_hijo = NEW.artcod  ;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;


    UPDATE STKINSUM set STKINSUM.ultima_compra = NEW.fecult, STKINSUM.costo_calculado = round(case when (NEW.artcos *
 STKINSUM.valcps / STKINSUM.valuso ) > 0 then 
	(NEW.artcos ) else 	STKINSUM.artcos end, 2) where STKINSUM.artcod = NEW.artcod and STKINSUM.siscod = '01';
	UPDATE STKPIEZA set recalc = recalc + 1 where STKPIEZA.articulo_hijo = NEW.artcod;

REPLACE INTO STK_COSTO_HIST set articulo_id = NEW.artcod, anio_hist = YEAR(NEW.fecult), mes_hist = MONTH(NEW.fecult), costo_hist = NEW.artcos;

  OPEN cur1;

  REPEAT
    FETCH cur1 INTO outerpadre;
    IF NOT done THEN

	select ifnull( (SELECT  idPadre FROM `STKPIEZA` where STKPIEZA.articulo_hijo = outerpadre limit 1) , '') into padre;

	while padre != '' do 
		update STKPIEZA set recalc = recalc + 1 where STKPIEZA.idPadre = padre;
	
		select ifnull( (SELECT  idPadre FROM `STKPIEZA` where STKPIEZA.articulo_hijo = padre limit 1) , '') into padre;
	end while;

    END IF;
  UNTIL done END REPEAT;

  CLOSE cur1;


END */;;
DELIMITER ;
