/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizoCostoArticuloArbol_insert` BEFORE INSERT ON `STKPIEZA` FOR EACH ROW
BEGIN 

set NEW.creacion_fecha = NOW();

set NEW.costo_automatico = (SELECT ifnull(costo_calculado,0) from STKINSUM where STKINSUM.siscod = '01' and STKINSUM.artcod = NEW.articulo_hijo);
IF ( (SELECT count(*) from STKPIEZA as PIEZA where  PIEZA.idPadre = NEW.articulo_hijo) > 0) then
set NEW.costo_automatico = ifnull((select costo from  (select sum(PIEZAS.cantidad * ifnull(PIEZAS.costo_automatico,0) + ( ifnull(PIEZAS.costo_automatico,0) / 100 * PIEZAS.recargo)) costo FROM STKPIEZA as PIEZAS where PIEZAS.idPadre = NEW.articulo_hijo) as PIEZTBL),0); 
END IF;

END */;;
DELIMITER ;
