/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizoCostoArticuloArbol_update` BEFORE UPDATE ON `STKPIEZA` FOR EACH ROW
BEGIN 

set NEW.modificacion_fecha = NOW();

set NEW.costo_automatico = ifnull((SELECT ifnull(costo_calculado, 0) from STKINSUM where STKINSUM.siscod = '01' and STKINSUM.artcod = NEW.articulo_hijo), 0);
IF ((SELECT count(*) from STKPIEZA as PIEZA where  PIEZA.idPadre = NEW.articulo_hijo and ((select tipocalculo_costo from STKINSUM where STKINSUM.artcod = NEW.articulo_hijo and STKINSUM.siscod = '01' limit 1 ) = 0) > 0)) then
set NEW.costo_automatico = ifnull(( select costo from  (select sum(PIEZAS.cantidad * PIEZAS.costo_automatico
* (1 + (PIEZAS.recargo / 100))) costo FROM STKPIEZA as PIEZAS where PIEZAS.idPadre = NEW.articulo_hijo) as PIEZTBL), 0); 
END IF;

END */;;
DELIMITER ;
