/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `stk_articulos_ai` AFTER INSERT ON `STK_ARTICULOS` FOR EACH ROW
BEGIN 
declare padre varchar(10) DEFAULT '';
        UPDATE STKPIEZA set STKPIEZA.costo_automatico = (select costo from ( select sum(INSUM.costo_calculado) as costo from STKPIEZA as PIEZA left join STK_ARTICULOS as INSUM on  INSUM.id_stkarticulo = PIEZA.articulo_hijo and INSUM.subsistema_id = '01' where PIEZA.articulo_hijo = NEW.id_stkarticulo) as piezas ) where STKPIEZA.articulo_hijo = NEW.id_stkarticulo;
SELECT  trim(idPadre)  into padre FROM `STKPIEZA` where STKPIEZA.articulo_hijo = NEW.id_stkarticulo  limit 1;
while padre != '' do 
	update STKPIEZA set recalc = recalc + 1 where STKPIEZA.idPadre = padre;
	select ifnull( (SELECT  idPadre FROM `STKPIEZA` where STKPIEZA.articulo_hijo = padre limit 1) , '') into padre;
end while;
END */;;
DELIMITER ;
