/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `STK_ARTICULOS_bu` BEFORE UPDATE ON `STK_ARTICULOS` FOR EACH ROW
begin

set NEW.stock_minimo = ceil(NEW.demprov * NEW.dem_diaria);
set NEW.stock_seguridad = ifnull(round((select sum(porcentaje_opcion) + 10 from STK_ATRIBUTO_OPCIONES inner join STK_ATRIBUTOS on stkatributo_id = id_stkatributo inner join STK_ATRIBUTOS_GRUPOS on id_stkgrupoatrib = stkgrupoatrib_id  inner join STK_ATRIBUTO_VALORES on STK_ATRIBUTO_VALORES.stkatributo_id = STK_ATRIBUTO_OPCIONES.stkatributo_id and valor_atributo = id_atribopciones where  STK_ATRIBUTO_VALORES.stkarticulo_id = NEW.id_stkarticulo and id_stkgrupoatrib = 1)/100 * NEW.demprov * NEW.dem_diaria, 0), 0);
set NEW.stock_reposicion = round(NEW.stock_seguridad + NEW.stock_minimo + (NEW.dem_diaria * NEW.dias_acopio), 2);
set NEW.stock_maximo = NEW.stock_seguridad + NEW.stock_minimo + NEW.stock_minimo;

set NEW.lote_optimo = (case when NEW.lote_minimo <= ((((NEW.stock_maximo - ceil(NEW.demprov * NEW.dem_diaria) ) div NEW.pack_embalaje) 
								+ (case when ( ( NEW.stock_maximo - ceil(NEW.demprov * NEW.dem_diaria) ) mod NEW.pack_embalaje ) != 0 then 1 else 0 end)) 
								* NEW.pack_embalaje)
							then ((((NEW.stock_maximo - ceil(NEW.demprov * NEW.dem_diaria) ) div NEW.pack_embalaje)
								+ (case when ( ( NEW.stock_maximo - ceil(NEW.demprov * NEW.dem_diaria) ) mod NEW.pack_embalaje ) != 0 then 1 else 0 end)) 
								* NEW.pack_embalaje)
							else ((NEW.lote_minimo div  NEW.pack_embalaje) + ( case when ( NEW.lote_minimo mod NEW.pack_embalaje != 0 ) then 1 else 0 end)) * NEW.pack_embalaje end) ;


end */;;
DELIMITER ;
