  `stkarticulopadre_id` varchar(100) NOT NULL,
  `stkarticulohijo_id` varchar(100) NOT NULL,
  `cantidad` decimal(10,2) NOT NULL DEFAULT '0.00',
  `recargo` decimal(10,2) NOT NULL,
  `cant_uso` decimal(10,2) NOT NULL,
  `costo_automatico` decimal(10,2) NOT NULL,
  `rec` decimal(10,2) NOT NULL,
  PRIMARY KEY (`id_stkbom`),
  KEY `articulo` (`stkarticulopadre_id`)
) ENGINE=InnoDB AUTO_INCREMENT=16511 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = '' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `STK_BOM_ENPROCESO_bi` BEFORE INSERT ON `STK_BOM_ENPROCESO` FOR EACH ROW
BEGIN 
set NEW.costo_automatico = (SELECT ifnull(costo_calculado,0) from STKINSUM where STKINSUM.siscod = '01' and STKINSUM.artcod = NEW.stkarticulohijo_id);
IF ( (SELECT count(*) from STK_BOM_ENPROCESO as PIEZA where  PIEZA.stkarticulopadre_id = NEW.stkarticulohijo_id) > 0) then
set NEW.costo_automatico = ifnull((select costo from  (select sum(PIEZAS.cantidad * ifnull(PIEZAS.costo_automatico,0) + ( ifnull(PIEZAS.costo_automatico,0) / 100 * PIEZAS.recargo)) costo FROM STK_BOM_ENPROCESO as PIEZAS where PIEZAS.stkarticulopadre_id = NEW.stkarticulohijo_id) as PIEZTBL),0); 
END IF;
END */;;
DELIMITER ;
