/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `STK_BOM_ENPROCESO_bu` BEFORE UPDATE ON `STK_BOM_ENPROCESO` FOR EACH ROW
BEGIN 
set NEW.costo_automatico = (SELECT ifnull(costo_calculado, 0) from STKINSUM where STKINSUM.siscod = '01' and STKINSUM.artcod = NEW.stkarticulohijo_id);
IF ((SELECT count(*) from STK_BOM_ENPROCESO as PIEZA where  PIEZA.stkarticulopadre_id = NEW.stkarticulohijo_id and ((select tipocalculo_costo from STKINSUM where STKINSUM.artcod = NEW.stkarticulohijo_id and STKINSUM.siscod = '01' limit 1 ) = 0) > 0)) then
set NEW.costo_automatico = ifnull(( select costo from  (select sum(PIEZAS.cantidad * PIEZAS.costo_automatico
* (1 + (PIEZAS.recargo / 100))) costo FROM STK_BOM_ENPROCESO as PIEZAS where PIEZAS.stkarticulopadre_id = NEW.stkarticulohijo_id) as PIEZTBL), 0); 
END IF;
END */;;
DELIMITER ;
