/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `STK_MOVIMIENTOS_bi` BEFORE INSERT ON `STK_MOVIMIENTOS` FOR EACH ROW
BEGIN

IF ISNULL(NEW.subsistema_id) OR NEW.subsistema_id = '' THEN
   set NEW.subsistema_id = '01';
end if;

IF  ifnull(NEW.stkdeposito_id, 0) = 0  THEN
   set NEW.stkdeposito_id = (select STK_LOCACION.stkdeposito_id from STK_LOCACION where id_stklocacion = NEW.stklocacion_id);
end if;

END */;;
DELIMITER ;
