/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizaStock_ins` AFTER INSERT ON `STK_MOVIMIENTOS` FOR EACH ROW
BEGIN



 REPLACE INTO STK_STOCKACTUAL 
          SET STK_STOCKACTUAL.stkarticulo_id = NEW.stkarticulo_id, 
              STK_STOCKACTUAL.stkdeposito_id = NEW.stkdeposito_id,
              STK_STOCKACTUAL.cantidad_stock = ifnull((SELECT sum( IF(tipo_concepto=0, 1, -1) * ifnull(cantidad,0) )
                                                         FROM STK_MOVIMIENTOS SM 
                                                    LEFT JOIN STK_CONCEPTOS SC 
                                                           ON SC.id_stkconcepto = SM.stkconcepto_id  
                                                        WHERE SM.stkarticulo_id = NEW.stkarticulo_id  and SM.subsistema_id = '01'

                                                          and SM.stkdeposito_id = NEW.stkdeposito_id), 0);

IF NEW.stklocacion_id != 0 THEN
INSERT IGNORE INTO STK_ARTICULO_LOCACION
          SET STK_ARTICULO_LOCACION.stkarticulo_id = NEW.stkarticulo_id, 
STK_ARTICULO_LOCACION.ultimo_mov = now(),
              STK_ARTICULO_LOCACION.stklocacion_id = NEW.stklocacion_id,
              STK_ARTICULO_LOCACION.stock_actual = ifnull((SELECT sum( IF(tipo_concepto=0, 1, -1) * ifnull(cantidad,0) )
                                                         FROM STK_MOVIMIENTOS SM 
                                                    LEFT JOIN STK_CONCEPTOS SC 
                                                           ON SC.id_stkconcepto = SM.stkconcepto_id  
                                                        WHERE SM.stkarticulo_id = NEW.stkarticulo_id  and SM.subsistema_id = '01'
                                                          and SM.stklocacion_id = NEW.stklocacion_id
                                                          and SM.stkdeposito_id = NEW.stkdeposito_id), 0); 
update STK_ARTICULO_LOCACION
          SET STK_ARTICULO_LOCACION.ultimo_mov = now(),
STK_ARTICULO_LOCACION.stock_actual = ifnull((SELECT sum( IF(tipo_concepto=0, 1, -1) * ifnull(cantidad,0) )
                                                         FROM STK_MOVIMIENTOS SM 
                                                    LEFT JOIN STK_CONCEPTOS SC 
                                                           ON SC.id_stkconcepto = SM.stkconcepto_id  
                                                        WHERE SM.stkarticulo_id = NEW.stkarticulo_id  and SM.subsistema_id = '01'
                                                          and SM.stklocacion_id = NEW.stklocacion_id
                                                          and SM.stkdeposito_id = NEW.stkdeposito_id), 0)
               where STK_ARTICULO_LOCACION.stkarticulo_id = NEW.stkarticulo_id and 
              STK_ARTICULO_LOCACION.stklocacion_id = NEW.stklocacion_id; 
END IF;

END */;;
DELIMITER ;
