CREATE DEFINER=`root`@`%` FUNCTION `CalcularFechaEntrega`(p_dias_habiles INT) RETURNS date
    DETERMINISTIC
BEGIN
    DECLARE v_dias_habiles_contados INT DEFAULT 0;
    DECLARE v_dias_corridos INT DEFAULT 0;
    DECLARE v_fecha_actual DATE;
    DECLARE v_es_fin_de_semana BOOLEAN;
    DECLARE v_es_feriado BOOLEAN;

    -- Empezamos desde hoy (o podrías pasar la fecha de inicio como parámetro)
    SET v_fecha_actual = CURDATE();

    -- El bucle se ejecuta hasta que hayamos encontrado los días hábiles necesarios
    WHILE v_dias_habiles_contados < p_dias_habiles DO
        
        -- Avanzamos un día en el calendario
        SET v_dias_corridos = v_dias_corridos + 1;
        SET v_fecha_actual = DATE_ADD(CURDATE(), INTERVAL v_dias_corridos DAY);
        
        -- 1. Chequeamos si es fin de semana (1=Domingo, 7=Sábado en estándar ODBC)
        SET v_es_fin_de_semana = (DAYOFWEEK(v_fecha_actual) IN (1, 7));
        
        -- 2. Chequeamos si es feriado (Usamos EXISTS que es más rápido que IN)
        SET v_es_feriado = EXISTS(SELECT 1 FROM FERIADOS WHERE idFeriado = v_fecha_actual);

        -- Solo si NO es fin de semana Y NO es feriado, contamos el día como hábil
        IF NOT v_es_fin_de_semana AND NOT v_es_feriado THEN
            SET v_dias_habiles_contados = v_dias_habiles_contados + 1;
        END IF;
        
    END WHILE;

    RETURN v_fecha_actual;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
