DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `calculoCalificacion`(`REGCUENTA` int, `FECHA` date, `MESES` int) RETURNS varchar(10) CHARSET utf8
    DETERMINISTIC
BEGIN
declare puntos   decimal(10,5);
declare recepciones   decimal(10,5);
declare calificacion   varchar(10);

set recepciones = (select sum(reccps) from OCPRECIB JOIN REG_CUENTA ON nro_cuenta = ctacod where  OCPRECIB.fecrec >= DATE_SUB(FECHA, INTERVAL 12 MONTH) AND REG_CUENTA.id_regcuenta = REGCUENTA limit 1 );

set puntos = (SELECT round(((select sum(peso) from MOVDEMERITO left join DEMERITO on DEMERITO.coddem = MOVDEMERITO.coddem where MOVDEMERITO.prvcod = REG_CUENTA.nro_cuenta and MOVDEMERITO.demfec >= DATE_SUB(FECHA,
 INTERVAL 12 MONTH) and MOVDEMERITO.coddem != 0) /  (select sum(reccps) from OCPRECIB where OCPRECIB.ctacod = REG_CUENTA.nro_cuenta and OCPRECIB.fecrec >= DATE_SUB(FECHA,
 INTERVAL 12 MONTH))) , 5) as puntos from REG_CUENTA where  REG_CUENTA.id_regcuenta = REGCUENTA limit 1 );

    CASE 
		WHEN  puntos >= 8 THEN
		   SET calificacion = 'X';
		WHEN  puntos >= 6 and puntos < 8 THEN
		   SET calificacion = 'C';
		WHEN  puntos >= 4 and puntos < 6 THEN
		   SET calificacion = 'B';
		WHEN  puntos < 4  THEN
		   SET calificacion = 'A';
             else 
 		   SET calificacion = 'A';

	END CASE;
if recepciones = 0 then
set calificacion = '-';
end if;

return calificacion;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
