CREATE DEFINER=`root`@`localhost` FUNCTION `cant_herr_act`(`ID_HERR` varchar(25), `USER` varchar(18), `FEC_CALC` date) RETURNS int(11)
    DETERMINISTIC
BEGIN
declare cant integer;

set cant = (SELECT COUNT(*) FROM HERRMOVS hacargo 
WHERE 
hacargo.usuario = USER 
and hacargo.id_herramienta = ID_HERR 
and hacargo.movher in (SELECT movher FROM CONCHERR where movtip = 2)
and hacargo.id_herramienta NOT IN
 (SELECT devueltas.id_herramienta FROM HERRMOVS devueltas WHERE devueltas.usuario = USER and devueltas.id_herramienta = ID_HERR and devueltas.movher in (SELECT movher FROM CONCHERR where movtip = 1) and devueltas.movfec <= FEC_CALC) 
and hacargo.movfec <= FEC_CALC
);

return cant;


END ;;
DELIMITER ;
