CREATE DEFINER=`root`@`localhost` FUNCTION `costo_reposicion`(`ARTICULO` varchar(20), `FECHA` date, `MONEDA` int) RETURNS decimal(14,4)
    DETERMINISTIC
BEGIN
declare cotiz DECIMAL(12,2);
declare costo DECIMAL(14,4);
declare bom integer;

set cotiz = (select cotizacion_genmonedahis from GEN_MONEDA_HIS where GEN_MONEDA_HIS.moneda_id = MONEDA and fecha_genmonedahis <= FECHA order by fecha_genmonedahis DESC limit 1);
set costo = (select cotiz * costo_proveedor + (costo_proveedor / 100 *  gasto_importacion) + (flete_local_ars / cotiz) from STK_COSTO_REPOSICION where stkarticulo_id = ARTICULO);
set bom = (select count(*) from STKPIEZA where IdPadre = ARTICULO);
if bom != 0 then 
	set costo = (select sum(cantidad *  (1 + recargo / 100)  * (cotiz * costo_proveedor + (costo_proveedor / 100 *  gasto_importacion) + (flete_local_ars / cotiz))) from STKPIEZA join STK_COSTO_REPOSICION ON articulo_hijo = stkarticulo_id WHERE IdPadre = ARTICULO);
end if;

return costo;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
