CREATE DEFINER=`root`@`localhost` FUNCTION `GEN_FN_COTIZACION`(`wmonedaid` int, `wfecha` varchar(10)) RETURNS decimal(18,4)
    DETERMINISTIC
BEGIN
	DECLARE resultado decimal(18,4);
	DECLARE done INT DEFAULT 0;

	DECLARE CurFuncion CURSOR FOR 	
	SELECT GEN_MONEDA_HIS.cotizacion_genmonedahis FROM GEN_MONEDA_HIS WHERE GEN_MONEDA_HIS.moneda_id = wmonedaid  and fecha_genmonedahis  <= wfecha order by fecha_genmonedahis desc limit 1;  

DECLARE CONTINUE HANDLER FOR SQLSTATE '02000' BEGIN END;
	OPEN CurFuncion;
    	FETCH CurFuncion  INTO resultado;
	IF done THEN 
	   set resultado = 1;
	END IF;
	set done =0 ;
	CLOSE CurFuncion; 

    IF isnull(resultado) THEN
        set resultado = 1;
    END IF;

    RETURN resultado;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
