CREATE DEFINER=`root`@`localhost` FUNCTION `getCalifProv`(`ID_REGCUENTA` int) RETURNS varchar(1) CHARSET utf8
    DETERMINISTIC
BEGIN

declare recepciones integer;
declare peso decimal(10,3);
declare nro_cuenta integer;
declare letra_calificacion varchar(1);

SET nro_cuenta = (SELECT REG_CUENTA.nro_cuenta FROM REG_CUENTA WHERE REG_CUENTA.id_regcuenta = ID_REGCUENTA AND REG_CUENTA.subsistema_id = '01' AND REG_CUENTA.baja = 0);

SET recepciones = IFNULL((SELECT COUNT(*) FROM OCPRECIB WHERE OCPRECIB.ctacod = nro_cuenta AND OCPRECIB.fecrec >= (curdate() - interval 12 month)), 0);

SET peso = IFNULL((SELECT SUM(DEMERITO.peso) FROM MOVDEMERITO
			LEFT JOIN DEMERITO ON DEMERITO.coddem = MOVDEMERITO.coddem
			WHERE MOVDEMERITO.prvcod = nro_cuenta
			      AND MOVDEMERITO.demfec >= (curdate() - interval 12 month)
			      AND MOVDEMERITO.coddem <> 0), 0);

SET letra_calificacion = (CASE WHEN IFNULL((peso / recepciones),0) = 0 THEN 'Z'
						   WHEN IFNULL((peso / recepciones),0) > 0 and IFNULL((peso / recepciones),0) < 4 THEN 'A'
	  					   WHEN IFNULL((peso / recepciones),0) >= 4 and IFNULL((peso / recepciones),0) < 6 THEN 'B'
						   WHEN IFNULL((peso / recepciones),0) >= 6 and IFNULL((peso / recepciones),0) < 8 THEN 'C' ELSE 'X' END);

RETURN letra_calificacion;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
