CREATE DEFINER=`root`@`localhost` FUNCTION `idturno_ingreso_seccion`(`NROFAB` int, `IDMOMENTO` int) RETURNS int(11)
    DETERMINISTIC
BEGIN
declare idturno   integer;
declare puestos integer;
declare offset integer;
declare linea integer;

declare ORD integer;

set linea = (select linea_id from TURNOSPRODUCCION where nrofab = NROFAB LIMIT 1);

set ORD = (select M.orden from MOMENTO M where M.idMomento = IDMOMENTO limit 1);


set puestos = (select count(*) -2 from MOMENTO AS MOM inner join POSICIONESFAB on POSICIONESFAB.idMomento = MOM.idMomento where MOM.linea_id=linea and MOM.reportar = 1 and MOM.orden < ORD) ;
if puestos = 0 then
set  puestos = 1;
end if;

set offset = puestos + (select ifnull(ajuste_dias,0) from MOMENTO where MOMENTO.linea_id = linea and MOMENTO.idMomento = IDMOMENTO limit 1);



set idturno = (select TURNOSPRODUCCION.nroturno from TURNOSPRODUCCION where TURNOSPRODUCCION.linea_id = linea and TURNOSPRODUCCION.fechaing >= (select TUR.fechaing from TURNOSPRODUCCION TUR where TUR.nrofab = NROFAB LIMIT 1) order by fechaing limit offset, 1 );


return idturno;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
