CREATE DEFINER=`root`@`localhost` FUNCTION `percepcionIIBB`(`REGCUENTA` int(11), `FECHA` date, `IMPORTE` decimal(10,2), `ALICUOTA` decimal(10,2), `BASE` decimal(10,2), `LETRA` varchar(1), `FLAG_CALCULO` int(1)) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN

   DECLARE tiene_percepciones int(11);
   DECLARE acumulado decimal(10,2);
   DECLARE saldo_anterior decimal(10,2);
   DECLARE percepcion decimal(10,2);

if (FLAG_CALCULO = 1) THEN

   SET tiene_percepciones = IFNULL((SELECT RM.id_regmovim FROM REG_MOVIMIENTOS RM 
                                              JOIN REG_CONCEPTOS RC ON RC.id_concepto = RM.concepto_id
                                                                                    AND RC.tipo_concepto = 1
                                              WHERE RM.regcuenta_id = REGCUENTA
                                                  AND RM.fecha_movimiento = FECHA
                                                  AND IFNULL(RM.importe_percepcion, 0) > 0
                                               ORDER BY RM.id_regmovim DESC LIMIT 1), 0);

   IF (tiene_percepciones > 0) THEN

      SET saldo_anterior = IFNULL((SELECT SUM(CASE WHEN LETRA = 'A' THEN RM.neto_movimiento ELSE RM.importe_movimiento END) FROM REG_MOVIMIENTOS RM 
                                              JOIN REG_CONCEPTOS RC ON RC.id_concepto = RM.concepto_id
                                                                                    AND RC.tipo_concepto = 1
                                              WHERE RM.regcuenta_id = REGCUENTA
                                                  AND RM.fecha_movimiento = FECHA
                                                  AND RM.id_regmovim > tiene_percepciones), 0);

   ELSEIF (tiene_percepciones = 0) THEN

      SET saldo_anterior = IFNULL((SELECT SUM(CASE WHEN LETRA = 'A' THEN RM.neto_movimiento ELSE RM.importe_movimiento END) FROM REG_MOVIMIENTOS RM 
                                              JOIN REG_CONCEPTOS RC ON RC.id_concepto = RM.concepto_id
                                                                                    AND RC.tipo_concepto = 1
                                              WHERE RM.regcuenta_id = REGCUENTA
                                                  AND RM.fecha_movimiento = FECHA), 0);
   END IF;

   SET acumulado = (saldo_anterior + IMPORTE);

   IF (acumulado > BASE) THEN

      SET percepcion = ((acumulado * ALICUOTA) / 100);

   ELSEIF (acumulado <= BASE) THEN

      SET percepcion = 0;

   END IF;   

ELSEIF ( FLAG_CALCULO = 0) THEN

    SET percepcion = 0;

END IF;

   RETURN percepcion;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP FUNCTION IF EXISTS `retencionGanancias` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8 */ ;
/*!50003 SET character_set_results = utf8 */ ;
/*!50003 SET collation_connection  = utf8_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
