CREATE DEFINER=`root`@`localhost` FUNCTION `retencionGanancias`(`CATEGORIA_GANANCIA` mediumint, `CATGANANCIAS_ID` mediumint, `SUMA_NETOS` decimal(10,2), `ACU_RET` decimal(10,2)) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN
DECLARE porret decimal(10,2);
DECLARE minimoretencion decimal(10,2);
DECLARE escala decimal(10,2);
DECLARE fijo decimal(10,2);
DECLARE minimo decimal(10,2);
DECLARE retencion decimal(10,2);

set porret = (select porcentaje_retencion / 100 from RET_TABLA_RETENCIONES where RET_TABLA_RETENCIONES.regcategoria_id = CATEGORIA_GANANCIA and RET_TABLA_RETENCIONES.retconcepto_id = CATGANANCIAS_ID LIMIT 1);

set minimoretencion = (select ifnull( RET_TABLA_RETENCIONES.minimo_retencion,0) from RET_TABLA_RETENCIONES where RET_TABLA_RETENCIONES.regcategoria_id = CATEGORIA_GANANCIA and RET_TABLA_RETENCIONES.retconcepto_id = CATGANANCIAS_ID LIMIT 1);

set escala = ifnull((select esc_porcen / 100 from RET_TABLA_RETENCIONES join RET_ESCALONES on RET_TABLA_RETENCIONES.id_rettabla = RET_ESCALONES.rettabla_id where RET_TABLA_RETENCIONES.regcategoria_id= CATEGORIA_GANANCIA and RET_TABLA_RETENCIONES.retconcepto_id = CATGANANCIAS_ID and (SUMA_NETOS - minimoretencion) > esc_minimo and (SUMA_NETOS - minimoretencion) <= esc_maximo limit 1),0);

set fijo = ifnull((select esc_fijo from RET_TABLA_RETENCIONES join RET_ESCALONES on RET_TABLA_RETENCIONES.id_rettabla = RET_ESCALONES.rettabla_id where RET_TABLA_RETENCIONES.regcategoria_id=CATEGORIA_GANANCIA and RET_TABLA_RETENCIONES.retconcepto_id = CATGANANCIAS_ID and (SUMA_NETOS - minimoretencion + 0) > esc_minimo and (SUMA_NETOS - minimoretencion  + 0) <= esc_maximo limit 1),0);

set minimo = ifnull((select esc_minimo from RET_TABLA_RETENCIONES join RET_ESCALONES on RET_TABLA_RETENCIONES.id_rettabla = RET_ESCALONES.rettabla_id where RET_TABLA_RETENCIONES.regcategoria_id= CATEGORIA_GANANCIA and RET_TABLA_RETENCIONES.retconcepto_id =  CATGANANCIAS_ID and (SUMA_NETOS - minimoretencion  + 0) > esc_minimo and (SUMA_NETOS - minimoretencion  + 0) <= esc_maximo limit 1),0);

set retencion = 0;
if (SUMA_NETOS >= minimoretencion) then
 IF (CATEGORIA_GANANCIA != 8  AND ((fijo + (SUMA_NETOS -  minimoretencion -  minimo   * (escala  + porret ) ) - ACU_RET ) > 20 ) ) THEN
  SET retencion = (fijo + (SUMA_NETOS -  minimoretencion -  minimo  ) * (escala  + porret ) ) - ACU_RET ;
 END IF;
END IF;

return retencion;
END ;;
DELIMITER ;
