DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `test_costo_repo`(`ARTICULO` varchar(20) CHARACTER SET 'utf8', `MONEDA` int(11), `COSTO_PROVEEDOR` decimal(10,4), `GASTO_IMPORTACION` decimal(10,4), `FLETE_LOCAL_ARS` decimal(10,4), `DESCUENTO_1` decimal(10,4), `DESCUENTO_2` decimal(10,4)) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN

DECLARE cotiz DECIMAL(12,2);

DECLARE costo DECIMAL(14,4);

DECLARE costo_sin_desc DECIMAL(14,4);

SET cotiz = (SELECT cotizacion_genmonedahis FROM GEN_MONEDA_HIS GMH WHERE GMH.moneda_id = MONEDA ORDER BY fecha_genmonedahis DESC LIMIT 1);

SET costo_sin_desc = ROUND(cotiz * (COSTO_PROVEEDOR + (COSTO_PROVEEDOR / 100 * GASTO_IMPORTACION))  + (FLETE_LOCAL_ARS / cotiz), 2);

SET costo = ((costo_sin_desc - ((costo_sin_desc * DESCUENTO_1) / 100)) - (((costo_sin_desc - ((costo_sin_desc * DESCUENTO_1) / 100)) * DESCUENTO_2) / 100));

RETURN costo;

END ;;
DELIMITER ;
