CREATE DEFINER=`root`@`localhost` FUNCTION `vcard_contacto`(`CONTACTO_ID` int) RETURNS text CHARSET utf8
    DETERMINISTIC
BEGIN
DECLARE select_var TEXT;
set select_var =(select 
concat( 'BEGIN:VCARD\n',  'VERSION:3.0\n',  'UID:', md5(CONCAT('contacto' , CCTCONTA.idconta)),'\n',
 'TITLE:', ifnull(CARGOS.nombre,''),'\n',
'ORG:',nombre_cuenta,'\n'
'N:;', UC_DELIMETER(LCASE(CCTCONTA.nombre), ' ', TRUE),';;;','\n',
'BDAY:',fecha_cump,'\n',
'CATEGORIES: contactos','\n',
'TEL;TYPE=WORK:',tel_cuenta,'\n',
'TEL;TYPE=WORK:',Telefono,'\n',
'TEL;TYPE=CELL:',movil,'\n',
'EMAIL;TYPE=WORK:',mail,'\n',
'NOTE:',nombre_fantasia,'\n',
'ADR:;;',cod_direccion,' ;',localidad_nombre,';', '' ,';;\n',
'END:VCARD','\n'
)  from CCTCONTA LEFT JOIN  REG_CUENTA on CCTCONTA.siscod = subsistema_id and ctacod = nro_cuenta 
left join CARGOS on CARGOS.siscod = subsistema_id and CARGOS.cargo = CCTCONTA.cargo where CCTCONTA.idconta = CONTACTO_ID);

return select_var;
END ;;
