CREATE DEFINER=`root`@`localhost` FUNCTION `vcard_personal`(`ID_PERSONAL` int) RETURNS text CHARSET utf8
    DETERMINISTIC
BEGIN
DECLARE select_var TEXT;
set select_var = (select concat( 'BEGIN:VCARD\n',  'VERSION:3.0\n',  'UID:', md5(CONCAT('personal' , ID_PERSONAL)),'\n',
 'TITLE:', (select descripcion from CATEGHISTORIA left join CATPERSONAL on CATPERSONAL.IdSindicato = CATEGHISTORIA.idSindicato
      and CATPERSONAL.IdCateg = CATEGHISTORIA.IdCateg  where CATEGHISTORIA.IdPersona = PERSONAL.IdPersona
      and CATEGHISTORIA.fechaDesde < CURDATE() order by CATEGHISTORIA.fechaDesde desc limit 1),'\n',
'N:', UC_DELIMETER(LCASE(PERSONAL.apellido), ' ', TRUE) ,';', UC_DELIMETER(LCASE(PERSONAL.Nombre), ' ', TRUE),';;;','\n',
'BDAY:',nacimiento,'\n',
'CATEGORIES:',SECCION.nombre,'\n',
'TEL;TYPE=WORK:',telefono,'\n',
'TEL;TYPE=CELL:',celular,'\n',
'EMAIL;TYPE=WORK:',email,'\n',
'NOTE:',patente,'\n',
'ADR:;;',calle, ' ',numero,' ;',LOCALIDADES.nombre,';',prvnom ,';;\n',
'END:VCARD','\n'
)  from PERSONAL
        left join FSMPROVS on FSMPROVS.prvcod = PERSONAL.idProvincia
        left join LOCALIDADES on idLocalidad = PERSONAL.localidad
    left join SECCION on SECCION.id_seccion = PERSONAL.id_seccion where IdPersona =ID_PERSONAL);

return select_var;
END ;;
