CREATE DEFINER=`root`@`localhost` PROCEDURE `generaCTBDia`(IN `FECHA_MOVIMIENTO` date, IN `CTBGRUPO_ID` int)
BEGIN
declare MOVIMIENTO_ID int;

DELETE FROM CTB_MOVIMIENTOS_DIA WHERE CTB_MOVIMIENTOS_DIA.fecha_movimiento = FECHA_MOVIMIENTO AND CTB_MOVIMIENTOS_DIA.ctbgrupo_id = CTBGRUPO_ID;

INSERT INTO CTB_MOVIMIENTOS_DIA set   fecha_movimiento = FECHA_MOVIMIENTO,  ctbgrupo_id = CTBGRUPO_ID,
ejercicio_id = (select id_ejercicio from CTB_EJERCICIOS WHERE comienza <= FECHA_MOVIMIENTO and finaliza >= FECHA_MOVIMIENTO limit 1);

SELECT LAST_INSERT_ID() INTO MOVIMIENTO_ID;

INSERT INTO CTB_DETALLES_DIA (cuenta_id, doh, importe, MOVIMIENTO_ID)  select 
cuenta_id,
(case when sum((case when doh = 0 then 1 else -1 end) * importe)  >= 0  then 0 else 1 end) as doh,
(case when sum((case when doh = 0 then 1 else -1 end) * importe)  >= 0 then sum((case when doh = 0 then 1 else -1 end) * importe)  else sum((case when doh = 0 then -1 else 1 end) * importe)  end) as importe,
MOVIMIENTO_ID

from CTB_MOVIMIENTOS 
JOIN CTB_DETALLES ON CTB_MOVIMIENTOS.id_movimiento = CTB_DETALLES.movimiento_id
where CTB_MOVIMIENTOS.fecha_movimiento = FECHA_MOVIMIENTO
and CTB_MOVIMIENTOS.ctbgrupo_id = CTBGRUPO_ID
and CTB_MOVIMIENTOS.concepto_id != 0 
group by CTB_DETALLES.cuenta_id
order by  doh, CTB_DETALLES.cuenta_id;


UPDATE CTB_MOVIMIENTOS_DIA 
SET debe =  (select sum(importe) from  CTB_DETALLES_DIA  DD where DD.MOVIMIENTO_ID = MOVIMIENTO_ID and DD.doh = 0)
      , haber = (select sum(importe) from  CTB_DETALLES_DIA  DD where DD.MOVIMIENTO_ID = MOVIMIENTO_ID  and DD.doh = 1)
where CTB_MOVIMIENTOS_DIA.id_movimiento = MOVIMIENTO_ID;

END ;;
DELIMITER ;
