CREATE DEFINER=`root`@`localhost` PROCEDURE `getCostConDto`(IN `ARTICULO` varchar(12), IN `MONEDA` integer, IN `FECHA` date, IN `LOGISTICO` integer, OUT `costo` decimal(14,4))
myproc:BEGIN
    declare cotiz DECIMAL(12,2);
    declare tmpcosto DECIMAL(14,4);
    declare canthijos DECIMAL(12,2);
    declare tipocalculo decimal (10,2);
    declare logis DECIMAL(10,2);

    DECLARE hijo_id char(32);
    DECLARE eol BOOLEAN;


    DECLARE hijos_cursor CURSOR FOR SELECT articulo_hijo FROM STKPIEZA  WHERE IdPadre = ARTICULO and bom_variacion_id = 0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET eol = TRUE;


    SET max_sp_recursion_depth=50;
    set MONEDA = ifnull((select moneda_id from STK_COSTO_REPOSICION where stkarticulo_id = ARTICULO limit 1), MONEDA);

    set cotiz = (select cotizacion_genmonedahis from GEN_MONEDA_HIS where GEN_MONEDA_HIS.moneda_id = MONEDA and fecha_genmonedahis <= FECHA order by fecha_genmonedahis DESC limit 1);
    set tipocalculo  = ifnull((select tipocalculo_costo from STK_ARTICULOS S where id_stkarticulo = ARTICULO and subsistema_id = '01' limit 1),1);




    set canthijos =  ifnull((select count(*) from STKPIEZA S where IdPadre = ARTICULO),0);
    IF canthijos = 0 or tipocalculo = 1
	THEN

     IF LOGISTICO = 1 THEN 
        set logis = (select ifnull(round((select porcentaje_region from REG_CUENTA join LOG_REGION on id_logregion = logregion_id where id_regcuenta = STK_COSTO_REPOSICION.regcuenta_id) , 4) ,
                                            round((select porcentaje_region from REG_CUENTA join LOG_REGION on id_logregion = logregion_id where id_regcuenta = STK_ARTICULOS.regcuenta_id and id_stkarticulo =  ARTICULO ) , 4)) 
from STK_ARTICULOS 
left join STK_COSTO_REPOSICION on stkarticulo_id =  ARTICULO where id_stkarticulo =  ARTICULO );
     ELSE 
       set logis = 100;
    END IF;
	set costo = logis * ifnull((select cotiz * ( 
		(costo_proveedor - (costo_proveedor / 100 * descuento_1) ) - ( (costo_proveedor - (costo_proveedor / 100 * descuento_1) ) / 100 * descuento_2)

		 ) + (costo_proveedor / 100 *  gasto_importacion) + (flete_local_ars / cotiz) from STK_COSTO_REPOSICION where stkarticulo_id = ARTICULO),0) / 100;
	leave myproc;
     ELSE 
     	set costo = 0;
     END IF;   

    OPEN hijos_cursor;
    hijos: LOOP
        FETCH hijos_cursor INTO hijo_id;

        IF eol 
            THEN
            CLOSE hijos_cursor;
            LEAVE hijos;
        ELSE
	   
            CALL getCostConDto(hijo_id, MONEDA, FECHA, LOGISTICO, tmpcosto);
/*
     IF LOGISTICO = 1 THEN 
        set logis = (select ifnull(round((select porcentaje_region from REG_CUENTA join LOG_REGION on id_logregion = logregion_id where id_regcuenta = STK_COSTO_REPOSICION.regcuenta_id) , 4) ,
                                            round((select porcentaje_region from REG_CUENTA join LOG_REGION on id_logregion = logregion_id where id_regcuenta = STK_ARTICULOS.regcuenta_id and id_stkarticulo =  hijo_id ) , 4)) 
from STK_ARTICULOS 
left join STK_COSTO_REPOSICION on stkarticulo_id =  hijo_id where id_stkarticulo =  hijo_id );
     ELSE 
       set logis = 100;
    END IF;
*/
            set costo = (costo + ifnull((select (tmpcosto * S.cantidad * (1 + S.recargo / 100)) from STKPIEZA S where S.articulo_hijo = hijo_id and IdPadre = ARTICULO and bom_variacion_id = 0 limit 1 ), tmpcosto)) ;
        END IF;


    END LOOP hijos;

END ;;
DELIMITER ;
