DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `ingresaCocheSeccion`(IN `NROFAB_ID` int, IN `MOMENTO_ID` int)
BEGIN
declare  primeraposicion INTEGER;
declare  proximaposicion INTEGER;
declare  posactual INTEGER;
declare  nro INTEGER;
declare yaexiste integer;
DECLARE eol BOOLEAN;
DECLARE coches CURSOR FOR select PROD_PATH_REGISTRO.nrofab_id, productpath_id from PROD_PATH_REGISTRO  where hora_salida = '0000-00-00 00:00:00' and productpath_id IN (select id_productpath from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID);
DECLARE CONTINUE HANDLER FOR NOT FOUND SET eol = TRUE;

set primeraposicion = (select id_productpath from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID and parent_productpath_id not in (select id_productpath from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID));

set yaexiste = ifnull( (select PROD_PATH_REGISTRO.nrofab_id from PROD_PATH_REGISTRO where PROD_PATH_REGISTRO.nrofab_id = NROFAB_ID and productpath_id = (select id_productpath from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID and parent_productpath_id not in (select id_productpath from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID))), 0);

/*
ANTES QUE NADA: le doy salida de la posicion actual (aunque sea de otra seccion)
*/
 
/* UPDATE PROD_PATH_REGISTRO set hora_salida = now() where nrofab_id = NROFAB_ID AND  hora_salida = '0000-00-00 00:00:00'; */ 


if (yaexiste = 0 and primeraposicion > 0) then


/* PARA CADA COCHE DE LA SECCION ACTUAL:*/
/*
1) lo ingreso en la proxima seccion
*/
OPEN coches;
linea: LOOP
        FETCH coches INTO nro, posactual;

        IF eol 
            THEN
            CLOSE coches;
            LEAVE linea;
        ELSE
            set proximaposicion = (select ifnull(id_productpath, 0) from PROD_PRODUCT_PATH join POSICIONESFAB on id_posicionfab = posicionfab_id where idMomento = MOMENTO_ID and parent_productpath_id = posactual);
            update PROD_PATH_REGISTRO set hora_salida = now() where productpath_id = posactual and hora_salida = '0000-00-00 00:00:00';
            IF  proximaposicion != 0 THEN
                INSERT IGNORE INTO PROD_PATH_REGISTRO set nrofab_id = nro, productpath_id = proximaposicion;
            END IF;

        END IF;


    END LOOP linea;

 


/* INSERTAR EL COCHE
Creo el registro del coche en la seccion
1) Busco primera posicion de la seccion
*/

/* 2) inserto el coche en la posicion */

 INSERT IGNORE INTO PROD_PATH_REGISTRO set nrofab_id = NROFAB_ID, productpath_id = primeraposicion; 

end if;

END ;;
DELIMITER ;
